const req = $('Diff Detail Endpoint').first().json;
const row = $input.first().json;
const ofile = String(req.query?.old_file ?? '').trim();
const nfile = String(req.query?.new_file ?? '').trim();
if (!row || row.diff_data == null) {
  return [{ json: { _status: 404, error: 'not_found', run_id: '', old_file: ofile, new_file: nfile, added: [], deleted: [], changed: [] } }];
}
const dd = row.diff_data || {};
const added = Array.isArray(dd.added) ? dd.added : [];
const deleted = Array.isArray(dd.deleted) ? dd.deleted : [];
function friendly(path) {
  const m = String(path).match(/\[['"]([^'"]+)['"]\]/g);
  if (m && m.length) return m.map((s) => s.replace(/\[['"]|['"]\]/g, '')).join('.');
  return String(path).replace(/^root\.?/, '');
}
function collect(node, out) {
  if (!node || typeof node !== 'object') return;
  for (const sec of ['values_changed', 'type_changes']) {
    if (node[sec] && typeof node[sec] === 'object') {
      for (const [p, v] of Object.entries(node[sec])) {
        if (v && typeof v === 'object') out[friendly(p)] = [v.old_value, v.new_value];
      }
    }
  }
  for (const k of Object.keys(node)) {
    if (k === 'values_changed' || k === 'type_changes') continue;
    if (node[k] && typeof node[k] === 'object') collect(node[k], out);
  }
}
const changedObj = (dd.changed && typeof dd.changed === 'object' && !Array.isArray(dd.changed)) ? dd.changed : {};
const changed = Object.keys(changedObj).map((guid) => {
  const out = {};
  collect(changedObj[guid], out);
  return { guid, changes: out };
});
return [{ json: { _status: 200, run_id: String(row.id ?? ''), old_file: row.old_file, new_file: row.new_file, added, deleted, changed } }];
